from sympy import tribonacci
from oeis_sequences.OEISsequences import bisection
def A003726(n):
    def f(x):
        s = bin(x)[-1:1:-1]
        return n+x-sum(tribonacci(i+2) for i in range(len(s)) if s[i]=='1' and not '111' in s[i+1:])-('111' not in s)
